var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"갑자기 바이크에 타라길래 어디로 가나 했더니…….","JPN":"いきなりバイクに乗れって言われたからどこに行くのかと思えば……","ENG":"As you suddenly asked to get on the bike, I was wondering where we’re headed to...","TWN":"突然叫我上車，我還以為是要去哪……"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"번화가에는 왜 온 거죠?","JPN":"繁華街には何の用ですか？","ENG":"Why did we come to the main street?","TWN":"為什麼要來大街上？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"실종자가 여기서 투숙하고 있었거든. 수도에 남은 몇 안 되는 호텔이야.","JPN":"失踪者がここに泊ってたから。首都に残る数少ないホテルだよ。","ENG":"The missing person was staying here. It is one of the few remaining hotels in the capital still standing.","TWN":"因為失蹤者曾經在這裡投宿，這裡是首都裡所剩無幾的飯店。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허어……. 딴 나라에서 돈 많이 벌었나 보네.","JPN":"へえ……他の国で結構儲けたのかな。","ENG":"Huh... He must have made a lot of money abroad.","TWN":"喔……看來他在其他國家賺很多喔？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇겠지. 실력이 있으면 어디에서나 자기 한 몸 건사할 수 있으니까.","JPN":"そうでしょうね。実力さえあればどこへ行っても生きていけるし。","ENG":"Right. You’ll survive anywhere if you’re skilled enough.","TWN":"應該是吧？只要有能力，去哪都能養活自己。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"묵고 있던 방에 무슨 단서가 있을 거야.","JPN":"泊ってた部屋に何か手がかりが残ってるはず。","ENG":"There must be some clues in the room he was staying in.","TWN":"在他住宿的房間裡應該會有線索。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"혼자 다녀오세요. 전 여기서 바이크나 지키고 있을 테니까.","JPN":"お一人でどうぞ。私はここでバイクでも見守ってますから。","ENG":"You can go in alone. I’ll stay here and watch over your motorcycle.","TWN":"你自己去找吧，我在這裡顧車。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"응? 어리다고 해서 토라졌어?","JPN":"え？　幼いって言ってすねちゃった？","ENG":"What? You still sulking because I called you a child back there?","TWN":"嗯？你是因為我說你年紀小，所以在耍脾氣嗎？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 딱히. 액면가 따지는 사람이 그쪽만 있는 것도 아니고.","JPN":"いいえ。別に。外見で評価する人はそちらだけでもないし。","ENG":"Nope. Not Exactly. Don’t jump to conclusions.","TWN":"有什麼好生氣的？會算的人可不是只有你。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저는 효율을 중시하는 편이거든요.","JPN":"私は効率を重視する方ですから。","ENG":"I just like doing things as efficiently as possible.","TWN":"我是重視效率的人。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"혹시 모를 교전에 대비해 체력을 아껴야죠. 조수 일은 정중하게 사양하겠습니다.","JPN":"もしもの交戦に備えて体力を保っておかないと。助手の仕事はご丁寧にお断りします。","ENG":"I need to save my strength for a possible confrontation. I'd like to decline your assistance.","TWN":"我要保留體力，這樣之後萬一遇到敵人才有體力開戰，請恕我拒絕當你的小助手。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"협조하지 않으면 상부에 보고할 때 네 험담을 잔뜩 써 줄게.","JPN":"協力しないと上層部に報告するとき、悪口をありったけ書いてやるけど。","ENG":"Look, if you don’t cooperate I might have to say some nasty stuff about you when I report to the top.","TWN":"你不幫忙的話，我會向長官投訴你。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"험담이라뇨?","JPN":"悪口？","ENG":"Nasty stuff?","TWN":"投訴我？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"임무에 비협조적인 것으로 보아 반란군과의 내통 가능성 있음. 한 줄이면 체포되는 마법의 문장이야.","JPN":"任務に非協力的なところから反乱軍と内通した可能性あり。一行で逮捕される魔法の文章よ。","ENG":"Uncooperative during the mission, might have potential communication with rebel forces. A magical sentence that will get you arrested in a single line.","TWN":"就說你不協助執行任務，很可能是與叛軍有勾結，簡單一句話就可以讓你被逮捕。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럼 이만 원대로 복귀해, 중사. 다음에 심문실에서 보자.","JPN":"では、元の部隊へ復帰しなさい、軍曹。次は尋問室でね。","ENG":"Go ahead. You can return to your squad, Sergeant. See ya in the interrogation room!","TWN":"你回去吧，中士。我們下次在審訊室見囉～"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"잠깐! 잠깐 기다려 봐요! 융통성 없게 왜 그래요?","JPN":"ちょっと！　ちょっと待って！　融通が利きませんね！","ENG":"Hold on! Wait a minute! Why are you being so inflexible?","TWN":"等一下！你先等一下啦！有什麼話好好說嘛～"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"애초에 전 헌병도 아니고 일개 보병이란 말입니다. 사람 찾는 일에는 다우징보다 쓸모없어요.","JPN":"だいたい私は憲兵でもないし、ただの歩兵なんです。人探しにはダウジングより役立たずなんですよ。","ENG":"First of all, I’m not a military policeman, I’m just a soldier. I don’t know the first thing about finding people.","TWN":"我又不是憲兵，我只是個小小的步兵，找人這種事我派不上用場啦！"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};